-- Rosera mass seed 3100 salons + default services ([RoseraSeed:v1])
-- Re-run safe: deletes prior seed batch first.

BEGIN;

SELECT 'c8a01110-2b3d-4e9f-9a1c-0d44a4b0c001'::uuid, 'ea1d1ff8-dd96-497b-949e-02d51a55e97c'::uuid, 'الظهران', 26.304, 50.103
WHERE NOT EXISTS (
  SELECT 1 FROM public.sa_cities c WHERE c.region_id = 'ea1d1ff8-dd96-497b-949e-02d51a55e97c'::uuid AND c.name_ar = 'الظهران'
);

DELETE FROM public.services WHERE business_id IN (
  SELECT id FROM public.businesses WHERE position('[RoseraSeed:v1]' in description_ar) > 0
);
DELETE FROM public.businesses WHERE position('[RoseraSeed:v1]' in description_ar) > 0;

















SELECT gen_random_uuid(), id, 'جلسة عناية وتجميل', 'care', 180.00, 60, true, true, 'imported'
FROM public.businesses WHERE position('[RoseraSeed:v1]' in description_ar) > 0;

COMMIT;
